// frontend/src/pages/SplashPage.js
import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

function SplashPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [fadeOut, setFadeOut] = useState(false);
  const [dots, setDots] = useState('...');

  useEffect(() => {
    const dotInterval = window.setInterval(() => {
      setDots((current) => {
        const nextCount = (current.length + 1) % 4;
        return '.'.repeat(nextCount);
      });
    }, 500);

    const fadeTimer = window.setTimeout(() => setFadeOut(true), 2500);
    const finishTimer = window.setTimeout(() => setLoading(false), 3000);

    return () => {
      window.clearInterval(dotInterval);
      window.clearTimeout(fadeTimer);
      window.clearTimeout(finishTimer);
    };
  }, []);

  return (
    <div className="splash-container">
      {loading ? (
        <div className={`loader-shell ${fadeOut ? 'fade-out' : ''}`} aria-busy="true" aria-label="Loading splash page">
          <div className="logo">💜</div>
          <h1>BTS: The Music That Shaped My Journey</h1>
          <div className="spinner" />
          <div className="loading-text">Loading<span className="dots">{dots}</span></div>
        </div>
      ) : (
        <div className="splash-content">
          <h1>Welcome to BTS Passion</h1>
          <p>Discover the world of BTS through music, stories, and the ARMY community.</p>
          <div className="splash-actions">
            <button className="btn btn-primary" onClick={() => navigate('/home')}>Explore Home</button>
            <button className="btn btn-secondary" onClick={() => navigate('/register')}>Join ARMY</button>
          </div>
        </div>
      )}

      <style>{`
        .splash-container {
          min-height: 100vh;
          display: flex;
          justify-content: center;
          align-items: center;
          padding: 2rem;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          text-align: center;
        }

        .loader-shell {
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 1rem;
          max-width: 740px;
          width: 100%;
        }

        .logo {
          font-size: 100px;
          margin-bottom: 0.5rem;
          animation: float 3s ease-in-out infinite;
        }

        .loader-shell h1 {
          font-size: clamp(2rem, 4vw, 3rem);
          margin: 0;
          text-shadow: 2px 2px 10px rgba(0, 0, 0, 0.25);
        }

        .spinner {
          width: 80px;
          height: 80px;
          border: 8px solid rgba(255, 255, 255, 0.3);
          border-top: 8px solid white;
          border-radius: 50%;
          margin: 1.5rem auto;
          animation: spin 1s linear infinite;
        }

        .loading-text {
          font-size: 1.15rem;
          color: rgba(255, 255, 255, 0.9);
        }

        .dots {
          display: inline-block;
          width: 30px;
        }

        .fade-out {
          animation: fadeOut 0.5s ease-out forwards;
        }

        @keyframes float {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-20px); }
        }

        .splash-content {
          max-width: 680px;
          width: 100%;
        }

        .splash-content h1 {
          font-size: clamp(3rem, 5vw, 4.5rem);
          margin-bottom: 1rem;
        }

        .splash-content p {
          font-size: 1.15rem;
          line-height: 1.8;
          margin-bottom: 2rem;
          color: rgba(255,255,255,0.92);
        }

        .splash-actions {
          display: flex;
          flex-wrap: wrap;
          gap: 1rem;
          justify-content: center;
        }

        .btn {
          min-width: 170px;
          padding: 1rem 1.75rem;
          border-radius: 999px;
          border: none;
          font-weight: 700;
          cursor: pointer;
          transition: transform 0.2s ease, opacity 0.2s ease;
        }

        .btn:hover {
          transform: translateY(-2px);
          opacity: 0.95;
        }

        .btn-primary {
          background-color: #ffffff;
          color: #5a2fa1;
        }

        .btn-secondary {
          background-color: rgba(255,255,255,0.15);
          color: white;
          border: 1px solid rgba(255,255,255,0.4);
        }

        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }

        @keyframes fadeOut {
          to { opacity: 0; }
        }

        @media (max-width: 640px) {
          .loader-shell h1, .splash-content h1 {
            font-size: 2.4rem;
          }
          .splash-actions {
            flex-direction: column;
          }
          .btn {
            width: 100%;
          }
        }
      `}</style>
    </div>
  );
}

export default SplashPage;
